// Pseudo drift score calculation
function computeDriftScore(trainDist, prodDist) {
  // use KL divergence as a simple drift metric
  let score = 0;
  const eps = 1e-9;
  const all = new Set([...Object.keys(trainDist), ...Object.keys(prodDist)]);
  for (const k of all) {
    const p = (trainDist[k] || 0) + eps;
    const q = (prodDist[k] || 0) + eps;
    score += p * Math.log(p / q);
  }
  return score;
}
```

