// Pseudo: subscribe to MongoDB change stream and forward to Event Hub
const { MongoClient } = require('mongodb');
const { EventHubProducerClient } = require('@azure/event-hubs');
async function streamChanges(uri, db, coll, ehConnectionString, ehName){
  const client = new MongoClient(uri);
  await client.connect();
  const collObj = client.db(db).collection(coll);
  const cursor = collObj.watch();
  const producer = new EventHubProducerClient(ehConnectionString, ehName);
  for await (const change of cursor) {
    await producer.sendBatch([{ body: change }]);
  }
}
```

