function processMQTTMessage(message) {
  const tracer = trace.getTracer('azure-functions');
  const span = tracer.startSpan('process-telemetry', {
    attributes: {
      'tenant.id': message.tenantId,
      'device.id': message.deviceId
    }
  });

  propagation.inject(context.with(trace.setSpan(context.active(), span), () => {
    const eventHubMessage = {
      payload: message.payload,
      _traceContext: {}  // W3C Trace Context injected here
    };
    sendToEventHub(eventHubMessage);
    span.end();
  }));
}

// Pseudocode: Circuit breaker for downstream failures
class CircuitBreaker {
  constructor(failureThreshold = 5, timeout = 60000) {
    this.failureCount = 0;
    this.failureThreshold = failureThreshold;
    this.timeout = timeout;
    this.state = 'CLOSED';
  }

  async execute(fn) {
    if (this.state === 'OPEN') {
      throw new Error('Circuit is OPEN - downstream service unavailable');
    }
    try {
      const result = await fn();
      this.onSuccess();
      return result;
    } catch (err) {
      this.onFailure();
      throw err;
    }
  }

  onSuccess() {
    this.failureCount = 0;
    this.state = 'CLOSED';
  }

  onFailure() {
    this.failureCount++;
    if (this.failureCount >= this.failureThreshold) {
      this.state = 'OPEN';
      setTimeout(() => { this.state = 'HALF_OPEN'; }, this.timeout);
    }
  }
}
```

## Key Takeaways

1. **OpenTelemetry** provides vendor-neutral instrumentation that spans edge to cloud
2. **Per-tenant dimensions** in metrics enable isolating issues without cross-tenant noise
3. **Dead-letter queues** are essential for preventing message loss during transient failures
4. **Circuit breakers** prevent cascade failures when downstream services are degraded

